export interface GetPermissionParams {
  accountNumber: string;
}

export interface PermissionValue {
  invoiceCashbackRedemption?: {
    redeemedAtDate: string | undefined;
  };
}

export interface PermissionDocument {
  codigoCliente: string;
  value: PermissionValue;
  status: 0 | 1;
}

export type PermissionDocumentInput = Omit<PermissionDocument, 'value'> & { value: string };

export interface PermissionDocumentResponse {
  data: PermissionDocument;
}

export enum PermissionStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

export interface PermissionState {
  hasRedeemed: boolean | null;
  status: PermissionStatus;
}
